"use strict";(self.webpackChunkddii=self.webpackChunkddii||[]).push([["7915"],{89826(e){e.exports=JSON.parse('{"tag":{"label":"Prometheus","permalink":"/docs/tags/prometheus","allTagsPath":"/docs/tags","count":1,"items":[{"id":"Prometheus/introduction","title":"Introduction to Prometheus","description":"Prometheus\uB294 \uB3D9\uC801 \uD074\uB77C\uC6B0\uB4DC \uD658\uACBD\uC744 \uBAA8\uB2C8\uD130\uB9C1\uD558\uB294 \uB370 \uD2B9\uD788 \uC801\uD569\uD55C \uBAA8\uB2C8\uD130\uB9C1 \uC2DC\uC2A4\uD15C \uBC0F \uC2DC\uACC4\uC5F4 \uB370\uC774\uD130\uBCA0\uC774\uC2A4\uC785\uB2C8\uB2E4. Prometheus\uB294 \uCC28\uC6D0(dimensional) \uB370\uC774\uD130 \uBAA8\uB378\uACFC \uAC15\uB825\uD55C \uCFFC\uB9AC \uC5B8\uC5B4(PromQL)\uB97C \uAC16\uCD94\uACE0 \uC788\uC73C\uBA70 \uACC4\uCE21(instrumentation), \uBA54\uD2B8\uB9AD(metrics) \uC218\uC9D1, \uC11C\uBE44\uC2A4 \uB514\uC2A4\uCEE4\uBC84\uB9AC(discovery) \uBC0F \uC5BC\uB7FF(alert)\uC640 \uAC19\uC740 \uAD6C\uC131\uC694\uC18C\uB4E4\uC744 \uD558\uB098\uC758 \uC5D0\uCF54\uC2DC\uC2A4\uD15C\uC5D0 \uD1B5\uD569\uD558\uC5EC \uC81C\uACF5\uD569\uB2C8\uB2E4. Prometheus\uB294 \uC6D0\uB798\uB294 SoundCloud\uC5D0\uC11C \uAC1C\uBC1C\uD588\uB358 \uC624\uD508\uC18C\uC2A4 \uBAA8\uB2C8\uD130\uB9C1 \uC2DC\uC2A4\uD15C\uC774\uC790 \uC54C\uB9BC \uB3C4\uAD6C\uC600\uC2B5\uB2C8\uB2E4. 2012\uB144\uC5D0 SoundCloud\uC758 \uC904\uB9AC\uC5B4\uC2A4 \uBCFC\uCE20(Julius Volz)\uC640 Google SRE\uD300\uC758 \uBE0C\uB77C\uC774\uC5B8 \uBE0C\uB77C\uC9C8(Brian Brazil)\uC744 \uC2DC\uC791\uC73C\uB85C \uB9CE\uC740 \uAE30\uC5C5\uACFC \uC870\uC9C1\uC5D0\uC11C \uD504\uB85C\uBA54\uD14C\uC6B0\uC2A4\uB97C \uCC44\uD0DD\uD588\uC73C\uBA70, \uAC1C\uBC1C\uC790, \uC0AC\uC6A9\uC790 \uCEE4\uBBA4\uB2C8\uD2F0 \uB610\uD55C \uB9E4\uC6B0 \uD65C\uBC1C\uD558\uAC8C \uAC1C\uBC1C\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uD604\uC7AC\uB294 Apache 2 License \uAE30\uBC18 \uB3C5\uB9BD\uD615 \uC624\uD508 \uC18C\uC2A4 \uD504\uB85C\uC81D\uD2B8\uC774\uBA70, \uC5B4\uB5A4 \uD68C\uC0AC\uC758 \uD1B5\uC81C\uB3C4 \uBC1B\uC9C0 \uC54A\uACE0 \uB3C5\uB9BD\uC801\uC73C\uB85C \uAD00\uB9AC\uB418\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uADF8\uB9AC\uACE0 \uD504\uB85C\uBA54\uD14C\uC6B0\uC2A4\uB294 2016\uB144\uC5D0 \uCFE0\uBC84\uB124\uD2F0\uC2A4\uB97C \uC787\uB294 \uB450 \uBC88\uC9F8 \uD638\uC2A4\uD305 \uD504\uB85C\uC81D\uD2B8\uB85C Cloud Native Computing Foundation(CNCF)\uC5D0 \uD569\uB958\uD588\uC2B5\uB2C8\uB2E4.","permalink":"/docs/Prometheus/introduction"}],"unlisted":false}}')}}]);